export function pngHasMeaningfulTransparency(bytes, opts = {}) {
  const cutoff = Math.round((opts.cutoff ?? 0.5) * 255);
  const minFraction = opts.minFraction ?? 0.005;
  const decoded = decodePngAlpha(buf);            // inflate + unfilter
  if (!decoded.alpha) return decoded.trnsPresent;  // palette/truecolor tRNS
  let transparent = 0;
  for (let i = 0; i < decoded.alpha.length; i += 1)
    if (decoded.alpha[i] < cutoff) transparent += 1;
  return transparent / decoded.alpha.length >= minFraction;
}

const cutout = srcTex ? textureHasAlpha(srcTex) : false;
const mat = {
  name: prMat.name || `mat_${m}`,
  pbrMetallicRoughness: { metallicFactor: 0, roughnessFactor: 1 },
  doubleSided: true,
  alphaMode: cutout ? 'MASK' : 'OPAQUE',
};
if (cutout) mat.alphaCutoff = 0.5;

if (const JsonValue* alpha = mat.get("alphaMode"); alpha && alpha->isString()) {
    const std::string mode = alpha->asString();
    gmat.alpha_blend = (mode == "MASK" || mode == "BLEND");
}
